index.html: <!DOCTYPE html>
<html lang="en">
<head>
	<meta charset="UTF-8">
	<meta name="viewport" content="width=device-width, initial-scale=1.0">
	<title>Morphing Shape</title>
	<link rel="stylesheet" href="styles.css">
</head>
<body class="flex justify-center items-center h-screen">
	<div id="shape" class="w-20 h-20 bg-red-500 rounded"></div>
<script src="script.js"></script>
</body>
</html>
styles.css: * { box-sizing: border-box; }
body { background-color: #333; }
#shape { transition: all 1s; width: 100%; height: 100%; background-color: red; border-radius: 0; }
#shape.circle { border-radius: 50%; }

script.js: const shape = document.getElementById('shape');
setInterval(() => {
	shape.classList.toggle('circle');
	const randomColor = Math.floor(Math.random() * 16777215).toString(16);
	shape.style.backgroundColor = `#${randomColor}`;
}, 1000);
